sql:
SELECT COUNT(*) AS active_config_option_count
FROM config_options
WHERE is_active = 1;

SELECT option_name
FROM config_options
WHERE is_active = 1;

external_knowledge:
- 'treasures of user opinions' refers to comments on configuration options; 
- 'current state of each setting' refers to the current value of configuration options; 
- 'vastness of the entire seabed's treasure' refers to the total number of comments across all records; 
- 'abundance of riches per treasure trove' refers to the number of comments per option; 
- 'wealth each diver has amassed' refers to the number of comments per user.

sql:
SELECT option_name, option_type, default_value
FROM config_options
WHERE is_active = 1;

SELECT method_name, description, is_active
FROM text_extraction_methods
WHERE is_active = 1;

SELECT AVG(CASE WHEN u.is_active = 0 THEN 1 ELSE 0 END) AS average_inactive_users
FROM option_history oh
INNER JOIN users u ON oh.changed_by = u.user_id;
